class UnitOfWork:
    def __init__(self, session_factory):
        self.session_factory = session_factory
        self._new = []
        self._dirty = []
        self._removed = []

    def __enter__(self):
        self.session = self.session_factory()
        return self

    def __exit__(self, *args):
        self.rollback()

    def commit(self):
        self.session.add_all(self._new)
        self.session.commit()
        self._new, self._dirty, self._removed = [], [], []

