import { initTRPC, TRPCError } from '@trpc/server';

const t = initTRPC.context().create();

const isAuthed = t.middleware(({ ctx, next }) => {
  if (!ctx.user) {
    throw new TRPCError({ code: 'UNAUTHORIZED' });
  }
  return next({ ctx: { user: ctx.user } });
});

const logger = t.middleware(async ({ path, type, next }) => {
  const start = Date.now();
  const result = await next();
  console.log(`${type} ${path} - ${Date.now() - start}ms`);
  return result;
});

export const publicProcedure = t.procedure.use(logger);
export const protectedProcedure = t.procedure.use(logger).use(isAuthed);

import { observable } from '@trpc/server/observable';
import { EventEmitter } from 'events';

const ee = new EventEmitter();

export const chatRouter = router({
  sendMessage: publicProcedure
    .input(z.object({ text: z.string(), user: z.string() }))
    .mutation(async ({ input }) => {
      const message = { ...input, id: Date.now() };
      ee.emit('message', message);
      return message;
    }),

  onMessage: publicProcedure
    .subscription(() => {
      return observable((emit) => {
        const onMessage = (msg) => emit.next(msg);
        ee.on('message', onMessage);
        return () => { ee.off('message', onMessage); };
      });
    }),
});

